rules.applicableAssetsQuery:
query ($options: VMOptions, $failedAssetsIdentifiers: [ID!]) {
  vms(
    options: $options
    where: {
      cloudProvider: "azure"
      AND: [
        { NOT: { extensions_SOME: null } }
        { NOT: { identifier_IN: $failedAssetsIdentifiers } }
      ]
    }
  ) {
    ...AssetFragment
  }
}
